CREATE TABLE IF NOT EXISTS public.user_profiles (
  id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  role text NOT NULL DEFAULT 'field_staff' CHECK (role IN ('superadmin','operator_admin','manager','finance','field_staff','warehouse','client')),
  operator_id uuid,
  client_id uuid,
  full_name text,
  telegram_user_id text,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);
ALTER TABLE public.user_profiles ENABLE ROW LEVEL SECURITY;
CREATE POLICY "users_own_profile" ON public.user_profiles FOR SELECT USING (auth.uid() = id);
CREATE POLICY "admins_manage_profiles" ON public.user_profiles FOR ALL USING (
  EXISTS (SELECT 1 FROM public.user_profiles WHERE id = auth.uid() AND role IN ('superadmin','operator_admin'))
);
